// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

import "forge-std/Test.sol";
import "../SafeTransfer.sol";

contract SafeTransferTest is Test {
    SafeTransfer safeTransfer;

    function setUp() public {
        safeTransfer = new SafeTransfer();
    }

    function testDeposit() public {
        uint256 amount = 1 ether;
        vm.deal(address(this), amount);
        safeTransfer.deposit{value: amount}();
        assertEq(safeTransfer.balances(address(this)), amount);
    }

    function testWithdraw() public {
        uint256 amount = 1 ether;
        vm.deal(address(this), amount);
        safeTransfer.deposit{value: amount}();
        safeTransfer.withdraw(amount);
        assertEq(safeTransfer.balances(address(this)), 0);
    }

    function testTransfer() public {
        uint256 amount = 1 ether;
        address recipient = address(0x123);
        vm.deal(address(this), amount);
        safeTransfer.deposit{value: amount}();
        safeTransfer.transfer(recipient, amount);
        assertEq(safeTransfer.balances(address(this)), 0);
        assertEq(safeTransfer.balances(recipient), amount);
    }

    function testReentrancyAttack() public {
        uint256 amount = 1 ether;
        vm.deal(address(this), amount);
        safeTransfer.deposit{value: amount}();

        ReentrancyAttack attacker = new ReentrancyAttack(address(safeTransfer));
        vm.expectRevert(bytes("ReentrancyGuard: reentrant call"));
        attacker.attack(amount);
    }
}

contract ReentrancyAttack {
    SafeTransfer safeTransfer;

    constructor(address _safeTransfer) {
        safeTransfer = SafeTransfer(_safeTransfer);
    }

    function attack(uint256 amount) external {
        safeTransfer.deposit{value: amount}();
        safeTransfer.withdraw(amount);
    }

    receive() external payable {
        if (address(safeTransfer).balance > 0) {
            safeTransfer.withdraw(address(safeTransfer).balance);
        }
    }
}
